export default function IndicatorsPanel({ context }: any) {
  return (
    <div style={{border:"1px solid #ddd", padding:20, marginBottom:20}}>
      <h3>Context Indicators</h3>
      <ul>
        {Object.entries(context.indicators).map(([key,value],i)=>(
          <li key={i}>
            {key}: {value}
          </li>
        ))}
      </ul>
    </div>
  )
}
