"use client"

import { useEffect, useState } from "react"

import { fetchPolicyEvaluation } from "@/lib/api"

import PolicyCard from "@/components/policy/PolicyCard"
import MetricsPanel from "@/components/metrics/MetricsPanel"
import IndicatorsPanel from "@/components/indicators/IndicatorsPanel"
import ScenarioComparison from "@/components/scenarios/ScenarioComparison"

export default function Home() {

  const [data,setData] = useState<any>(null)

  useEffect(()=>{
    fetchPolicyEvaluation().then(setData)
  },[])

  if(!data){
    return <div style={{padding:40}}>Loading policy analysis...</div>
  }

  return (

    <main style={{padding:40,fontFamily:"sans-serif"}}>

      <h1>HodioPolitica</h1>

      <PolicyCard policy={data.policy} />

      <IndicatorsPanel context={data.policy ? data : {indicators:{}}} />

      <MetricsPanel metrics={data.metrics} />

      <ScenarioComparison scenarios={data.scenarios} />

    </main>

  )

}
