"use client"

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer
} from "recharts"

export default function MetricsChart({ metrics }: any) {

  const data = metrics.map((m:any)=>({
    name: m.metricName,
    value: m.value
  }))

  return (
    <div style={{width:"100%",height:300}}>
      <ResponsiveContainer>
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name"/>
          <YAxis/>
          <Tooltip/>
          <Bar dataKey="value" fill="#8884d8"/>
        </BarChart>
      </ResponsiveContainer>
    </div>
  )
}
