"use client"

import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer
} from "recharts"

export default function ScenarioChart({ scenarios }: any) {

  if(!scenarios.length) return null

  const metricKeys = Object.keys(scenarios[0].projectedImpact)

  const data = metricKeys.map((metric)=>{

    const row:any = { metric }

    scenarios.forEach((s:any)=>{
      row[s.name] = s.projectedImpact[metric]
    })

    return row
  })

  return (
    <div style={{width:"100%",height:350}}>
      <ResponsiveContainer>
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3"/>
          <XAxis dataKey="metric"/>
          <YAxis/>
          <Tooltip/>
          {scenarios.map((s:any,i:number)=>(
            <Bar key={i} dataKey={s.name} fill={["#8884d8","#82ca9d","#ff7f50"][i%3]}/>
          ))}
        </BarChart>
      </ResponsiveContainer>
    </div>
  )

}
